// // This module designs a 3-bit binary down-counter that decrements on each positive edge of the clock signal (clk). If the reset signal (rst) is asserted, the counter resets to seven. The counter wraps around to seven after reaching its minimum value of zero (3'b000). The current count value is reflected in the output (out).
module top_module(
    input clk,
    input rst,
    output reg [2:0] out
);reg [2:0] count;

always @(posedge clk) begin
    if (rst) begin
        count <= 3'b0;
    end else if (count == 3'b111) begin
        count <= 3'b0;
    end else begin
        count <= count + 1;
    end
end

assign out = count;

endmodule
